const item = $input.first()
const binaries = item.binary || {}

let pdfKey = null
let pdfBinary = null
for (const [key, bin] of Object.entries(binaries)) {
  const isPdf = bin.mimeType === 'application/pdf' ||
    (bin.fileName || '').toLowerCase().endsWith('.pdf')
  if (isPdf) { pdfKey = key; pdfBinary = bin; break }
}

if (!pdfBinary || !pdfKey) {
  return [{ json: { hasPdf: false } }]
}

const rawName = pdfBinary.fileName || 'invoice.pdf'
const fileName = `${Date.now()}_${rawName.replace(/[^a-zA-Z0-9._-]/g, '_')}`

const f = item.json.from
const emailFrom = !f ? ''
  : typeof f === 'string' ? f
  : f.text ? f.text
  : f.value?.[0]?.address ?? String(f)

return [{
  json: {
    hasPdf: true,
    fileName,
    emailSubject: item.json.subject || '',
    emailFrom
  },
  binary: { data: item.binary[pdfKey] }
}]

// $json.data = base64 string von Extract from File
// fileName aus PDF extrahieren holen (wird von Extract from File nicht weitergegeben)
const pdfBase64    = $json.data
const pdfNode      = $('PDF extrahieren').first().json
const fileName     = pdfNode.fileName
const emailSubject = pdfNode.emailSubject
const emailFrom    = pdfNode.emailFrom

const body = {
  contents: [{ parts: [
    { inline_data: { mime_type: 'application/pdf', data: pdfBase64 } },
    { text: 'Ist dieses Dokument eine Rechnung, ein Kassenbon oder eine Quittung? Antworte NUR mit JSON: {"is_invoice": true} oder {"is_invoice": false}. Lieferscheine, Angebote, Newsletter, Bestellbestätigungen ohne Zahlungsaufforderung, Verträge und Mahnungen sind KEINE Rechnungen.' }
  ]}],
  generationConfig: {
    response_mime_type: 'application/json',
    response_schema: {
      type: 'OBJECT',
      properties: { is_invoice: { type: 'BOOLEAN' } },
      required: ['is_invoice']
    }
  }
}

return [{
  json: { checkBody: JSON.stringify(body), pdfBase64, fileName, emailSubject, emailFrom },
  binary: $input.first().binary
}]

const rawText = $json.candidates?.[0]?.content?.parts?.[0]?.text
let isInvoice = false
try {
  const parsed = typeof rawText === 'string' ? JSON.parse(rawText) : (rawText ?? {})
  isInvoice = parsed.is_invoice === true
} catch {}

const prev = $('Rechnungsprüfung vorbereiten').first().json

return [{
  json: {
    isInvoice,
    pdfBase64:    prev.pdfBase64,
    fileName:     prev.fileName,
    emailSubject: prev.emailSubject,
    emailFrom:    prev.emailFrom
  },
  binary: $('Rechnungsprüfung vorbereiten').first().binary
}]

const all = $input.all()
const kategorien = all.map(item => ({ wert: item.json.wert, beschreibung: item.json.beschreibung }))
const prev = $('Rechnungsprüfung vorbereiten').first().json
return [{ json: { kategorien, pdfBase64: prev.pdfBase64, fileName: prev.fileName } }]

const CARD_MAP = {
  '1380': 'spesen_philipp_1380',
  '0744': 'spesen_philipp_0744',
  '6362': 'firmenkarte_6362',
  '0660': 'firmenkarte_0660'
}

function normalizeDate(raw) {
  if (!raw) return null
  const s = String(raw).trim()
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s
  if (s.includes('.')) {
    const [d, m, y] = s.split('.')
    if (d && m && y) return `${y.trim()}-${m.trim().padStart(2,'0')}-${d.trim().padStart(2,'0')}`
  }
  const p = new Date(s)
  return isNaN(p.getTime()) ? null : p.toISOString().split('T')[0]
}

const rawText = $json.candidates?.[0]?.content?.parts?.[0]?.text
let ocr = typeof rawText === 'string' ? JSON.parse(rawText) : (rawText ?? {})

if (ocr.is_proforma) {
  ocr = { ...ocr, tax_rate: null, tax_amount_10: null, tax_amount_20: null, net_amount_10: null, net_amount_20: null }
}
if (ocr.tax_rate === 19) ocr = { ...ocr, tax_rate: 20 }
if (!ocr.is_proforma && (ocr.tax_rate === null || ocr.tax_rate === undefined) && ocr.net_amount && !ocr.net_amount_0) ocr = { ...ocr, tax_rate: 20 }

const n10 = ocr.net_amount_10 ?? 0
const n20 = ocr.net_amount_20 ?? 0
const n0  = ocr.net_amount_0  ?? 0
const sum = n10 + n20 + n0
const netto = sum > 0 ? Math.round(sum * 100) / 100 : (ocr.net_amount ?? 0)

const digits = ocr.card_last_four ? String(ocr.card_last_four).trim() : null
const karte  = digits ? (CARD_MAP[digits] ?? 'sonstige') : null

const fileName = $('PDF extrahieren').first().json.fileName
const pdfUrl = `https://emrjxrtxlvyrwplglkzk.supabase.co/storage/v1/object/public/rechnungen/${encodeURIComponent(fileName)}`

return [{
  json: {
    rechnungsnr:    ocr.invoice_number?.trim() || `EMAIL-${Date.now()}`,
    rechnungsdatum: normalizeDate(ocr.invoice_date) || null,
    faelligkeit:    normalizeDate(ocr.due_date)     || null,
    betrag:         netto,
    ust_satz:       ocr.is_proforma ? 0 : (ocr.tax_rate !== null && ocr.tax_rate !== undefined ? ocr.tax_rate : 20),
    rechnungstyp:   ocr.invoice_type || null,
    betrag_10:      ocr.net_amount_10 ?? null,
    betrag_20:      ocr.net_amount_20 ?? null,
    betrag_0:       ocr.net_amount_0  ?? null,
    mwst_10:        ocr.tax_amount_10 ?? null,
    mwst_20:        ocr.tax_amount_20 ?? null,
    karte,
    pdf_url:        pdfUrl,
    status:         'eingegangen',
    ocr_json:       ocr,
    supplier_name:  ocr.supplier_name || 'Unbekannter Lieferant'
  }
}]
